{"content":"// Neon Mahjong VR - Main Game System

import {
  createSystem,
  InputComponent,
  World,
} from '@iwsdk/core';
import { GameState } from '../state';
import { TileRenderer } from '../renderer';
import { AudioManager } from '../audio';
import { LAYOUTS, GAME_MODES, type GameMode } from '../data';

export type GameScreen = 'title' | 'modeselect' | 'layoutselect' | 'countdown'
  | 'playing' | 'pause' | 'gameover' | 'achievements' | 'stats'
  | 'settings' | 'skins' | 'help' | 'leaderboard' | 'tutorial';

export class GameSystem extends createSystem({}) {
  private state!: GameState;
  private renderer!: TileRenderer;
  private audio!: AudioManager;
  private world!: World;

  _screen: GameScreen = 'title';
  private _onScreenChange: ((screen: GameScreen) => void) | null = null;

  // Input
  private mouseDown = false;
  private clickX = 0;
  private clickY = 0;
  private inputCooldown = 0;
  private stickCooldown = 0;
  private prevTrigger = false;
  private prevA = false;
  private prevB = false;
  private prevGrip = false;

  // Countdown
  private countdownValue = 3;
  private countdownTimer = 0;

  // Hint
  private hintPair: [number, number] | null = null;
  private hintTimer = 0;

  // Pending game start
  private pendingMode: GameMode = 'classic';
  private pendingLayout = 0;
  private showTutorial = false;

  setRefs(refs: {
    state: GameState;
    renderer: TileRenderer;
    audio: AudioManager;
    world: World;
  }): void {
    this.state = refs.state;
    this.renderer = refs.renderer;
    this.audio = refs.audio;
    this.world = refs.world;

    // Wire state callbacks
    this.state.onMatch = (a, b) => {
      this.renderer.removeTile(a.idx);
      this.renderer.removeTile(b.idx);
      this.audio.playMatch();
      this.clearHints();
    };
    this.state.onSelect = (t) => {
      this.renderer.setTileSelected(t.idx, true);
      this.audio.playSelect();
    };
    this.state.onDeselect = () => {
      if (this.state.board) {
        for (const tile of this.state.board.tiles) {
          if (!tile.removed) this.renderer.setTileSelected(tile.idx, false);
        }
      }
      this.audio.playDeselect();
    };
    this.state.onCombo = (combo) => {
      this.audio.playCombo(combo);
    };
    this.state.onShuffle = () => {
      this.renderer.refreshAllTiles();
      this.audio.playShuffle();
    };
    this.state.onGameOver = (won) => {
      if (won) this.audio.playWin();
      else this.audio.playLose();
      this.audio.stopMusic();
      this._screen = 'gameover';
      this._onScreenChange?.('gameover');
    };
    this.state.onAchievement = (_id) => {
      this.audio.playAchievement();
    };

    // Mouse input
    const canvas = this.world.renderer.domElement;
    canvas.addEventListener('click', (e: MouseEvent) => {
      this.audio.init();
      if (this._screen !== 'playing') return;
      const rect = canvas.getBoundingClientRect();
      const ndcX = ((e.clientX - rect.left) / rect.width) * 2 - 1;
      const ndcY = -((e.clientY - rect.top) / rect.height) * 2 + 1;
      const hitIdx = this.renderer.raycast(ndcX, ndcY, this.world.camera);
      if (hitIdx !== null) {
        this.state.selectTile(hitIdx);
      }
    });

    // Keyboard
    document.addEventListener('keydown', (e: KeyboardEvent) => {
      this.audio.init();
      this.handleKeyDown(e.key.toLowerCase());
    });

    // Check if tutorial needed
    this.showTutorial = !localStorage.getItem('neon-mahjong-tutorial-done');
  }

  onScreenChange(cb: (screen: GameScreen) => void): void {
    this._onScreenChange = cb;
  }

  // ── Screen Management ─────────────────────────────────────
  goTo(screen: GameScreen): void {
    this._screen = screen;
    this._onScreenChange?.(screen);
  }

  // ── Game Flow ─────────────────────────────────────────────
  startGameSetup(mode: GameMode): void {
    this.pendingMode = mode;
    this.goTo('layoutselect');
  }

  startWithLayout(layoutIdx: number): void {
    this.pendingLayout = layoutIdx;

    if (this.showTutorial) {
      this.showTutorial = false;
      localStorage.setItem('neon-mahjong-tutorial-done', '1');
      this.goTo('tutorial');
      return;
    }

    this.beginCountdown();
  }

  beginCountdown(): void {
    this.countdownValue = 3;
    this.countdownTimer = 0;
    this.goTo('countdown');
    this.audio.playCountdown();
  }

  startGame(): void {
    this.state.startGame(this.pendingMode, this.pendingLayout);
    this.renderer.buildBoard();
    this.audio.startMusic();
    this.goTo('playing');
  }

  // ── Input ─────────────────────────────────────────────────
  private handleKeyDown(key: string): void {
    if (this._screen === 'playing') {
      if (key === 'escape' || key === 'p') {
        this.togglePause();
      } else if (key === 'h') {
        this.requestHint();
      } else if (key === 's') {
        this.requestShuffle();
      } else if (key === 'z') {
        this.state.undo();
        this.renderer.buildBoard(); // Rebuild after undo
      }
    } else if (this._screen === 'pause') {
      if (key === 'escape' || key === 'p') {
        this.togglePause();
      }
    }
  }

  togglePause(): void {
    if (!this.state.board) return;
    if (this._screen === 'playing') {
      this.state.board.paused = true;
      this.goTo('pause');
    } else if (this._screen === 'pause') {
      this.state.board.paused = false;
      this.goTo('playing');
    }
  }

  requestHint(): void {
    this.clearHints();
    const hint = this.state.useHint();
    if (hint) {
      this.hintPair = hint;
      this.hintTimer = 3; // Show for 3 seconds
      this.renderer.setTileHint(hint[0], true);
      this.renderer.setTileHint(hint[1], true);
      this.audio.playHint();
    } else {
      this.audio.playInvalid();
    }
  }

  requestShuffle(): void {
    if (!this.state.shuffleBoard()) {
      this.audio.playInvalid();
    }
  }

  private clearHints(): void {
    if (this.hintPair) {
      this.renderer.setTileHint(this.hintPair[0], false);
      this.renderer.setTileHint(this.hintPair[1], false);
      this.hintPair = null;
    }
    this.hintTimer = 0;
  }

  // ── Update Loop ───────────────────────────────────────────
  update(delta: number, _time: number): void {
    const dt = delta / 1000; // Convert to seconds

    if (this.inputCooldown > 0) this.inputCooldown -= dt;
    if (this.stickCooldown > 0) this.stickCooldown -= dt;

    // XR input
    this.handleXRInput();

    if (this._screen === 'countdown') {
      this.countdownTimer += dt;
      if (this.countdownTimer >= 1) {
        this.countdownTimer = 0;
        this.countdownValue--;
        if (this.countdownValue <= 0) {
          this.audio.playCountdownGo();
          this.startGame();
        } else {
          this.audio.playCountdown();
          this._onScreenChange?.('countdown');
        }
      }
    }

    if (this._screen === 'playing') {
      this.state.tick(dt);

      // Hint timer
      if (this.hintTimer > 0) {
        this.hintTimer -= dt;
        if (this.hintTimer <= 0) {
          this.clearHints();
        }
      }
    }
  }

  private handleXRInput(): void {
    if (this._screen !== 'playing') return;

    const input = this.world.input;
    if (!input) return;

    // Right controller trigger for tile selection
    const triggerVal = input.getButtonValue?.(InputComponent.Trigger) ?? 0;
    const triggerDown = triggerVal > 0.5;
    if (triggerDown && !this.prevTrigger) {
      // Trigger pressed — use XR ray for tile pick
      // The PanelUI pointer handles this natively, but for board tiles:
      const controllers = input.getControllers?.() ?? [];
      if (controllers.length > 0) {
        const ctrl = controllers[0];
        if (ctrl && ctrl.targetRaySpace) {
          // Raycast from controller
          // Note: XR input raycasting handled by pointer events in IWSDK
        }
      }
    }
    this.prevTrigger = triggerDown;

    // A button = hint
    const aVal = input.getButtonValue?.(InputComponent.ButtonA) ?? 0;
    const aDown = aVal > 0.5;
    if (aDown && !this.prevA && this.inputCooldown <= 0) {
      this.requestHint();
      this.inputCooldown = 0.3;
    }
    this.prevA = aDown;

    // B button = pause
    const bVal = input.getButtonValue?.(InputComponent.ButtonB) ?? 0;
    const bDown = bVal > 0.5;
    if (bDown && !this.prevB && this.inputCooldown <= 0) {
      this.togglePause();
      this.inputCooldown = 0.3;
    }
    this.prevB = bDown;

    // Grip = shuffle
    const gripVal = input.getButtonValue?.(InputComponent.Grip) ?? 0;
    const gripDown = gripVal > 0.5;
    if (gripDown && !this.prevGrip && this.inputCooldown <= 0) {
      this.requestShuffle();
      this.inputCooldown = 0.3;
    }
    this.prevGrip = gripDown;

    // Thumbstick = rotate board (conceptual: rotate the board group)
    if (this.stickCooldown <= 0) {
      const axes = input.getAxesValues?.(InputComponent.Thumbstick);
      if (axes) {
        const x = typeof axes === 'object' && 'x' in axes ? (axes as any).x : 0;
        if (Math.abs(x) > 0.5) {
          const boardGroup = this.renderer['boardGroup'];
          if (boardGroup) {
            boardGroup.rotation.y += x > 0 ? 0.3 : -0.3;
          }
          this.stickCooldown = 0.25;
        }
      }
    }
  }
