{"content":"// Neon Mahjong VR - Entry Point

import {
  World,
  PanelUI,
  Follower,
  ScreenSpace,
} from '@iwsdk/core';
import { GameState } from './state';
import { TileRenderer } from './renderer';
import { AudioManager } from './audio';
import { GameSystem } from './systems/game-system';
import { UISystem } from './systems/ui-system';

async function main(): Promise<void> {
  const container = document.getElementById('app') as HTMLDivElement;

  const world = await World.create(container, {
    xr: { offer: 'once' },
    browserControls: true,
    render: {
      near: 0.01,
      far: 50,
    },
    features: {
      locomotion: false,
      grabbing: false,
      physics: false,
    },
  });

  // Camera position - looking at the board
  world.camera.position.set(0, 2.2, 1.0);
  world.camera.lookAt(0, 0.8, -1.5);

  // Core managers
  const state = new GameState();
  const audio = new AudioManager();
  const renderer = new TileRenderer(world, state);

  // Register ECS systems
  world.registerSystem(GameSystem);
  world.registerSystem(UISystem);

  const gameSystem = world.getSystem(GameSystem)!;
  gameSystem.setRefs({ state, renderer, audio, world });

  const uiSystem = world.getSystem(UISystem)!;
  uiSystem.setRefs({ state, gameSystem, audio, renderer });

  // Create panels
  createPanels(world);

  // Init audio on first interaction
  const initAudio = () => audio.init();
  document.addEventListener('click', initAudio, { once: true });
  document.addEventListener('touchstart', initAudio, { once: true });
}

function createPanels(world: World): void {
  // Title screen (center, visible at start)
  const titleEntity = world.createTransformEntity();
  titleEntity.object3D!.position.set(0, 1.1, -1.5);
  titleEntity.addComponent(PanelUI, { config: './ui/title.json' });

  // HUD (top of view, head-locked)
  const hudEntity = world.createTransformEntity();
  hudEntity.object3D!.position.set(0, 1.8, -1.5);
  hudEntity.addComponent(PanelUI, { config: './ui/hud.json' });
  hudEntity.object3D!.visible = false;

  // Mode select
  const modeEntity = world.createTransformEntity();
  modeEntity.object3D!.position.set(0, 1.1, -1.5);
  modeEntity.addComponent(PanelUI, { config: './ui/modeselect.json' });
  modeEntity.object3D!.visible = false;

  // Layout select
  const layoutEntity = world.createTransformEntity();
  layoutEntity.object3D!.position.set(0, 1.1, -1.5);
  layoutEntity.addComponent(PanelUI, { config: './ui/layout.json' });
  layoutEntity.object3D!.visible = false;

  // Game over
  const goEntity = world.createTransformEntity();
  goEntity.object3D!.position.set(0, 1.1, -1.5);
  goEntity.addComponent(PanelUI, { config: './ui/gameover.json' });
  goEntity.object3D!.visible = false;

  // Pause
  const pauseEntity = world.createTransformEntity();
  pauseEntity.object3D!.position.set(0, 1.1, -1.5);
  pauseEntity.addComponent(PanelUI, { config: './ui/pause.json' });
  pauseEntity.object3D!.visible = false;

  // Achievements
  const achEntity = world.createTransformEntity();
  achEntity.object3D!.position.set(0, 1.0, -1.5);
  achEntity.addComponent(PanelUI, { config: './ui/achievements.json' });
  achEntity.object3D!.visible = false;

  // Stats
  const statsEntity = world.createTransformEntity();
  statsEntity.object3D!.position.set(0, 1.1, -1.5);
  statsEntity.addComponent(PanelUI, { config: './ui/stats.json' });
  statsEntity.object3D!.visible = false;

  // Settings
  const settingsEntity = world.createTransformEntity();
  settingsEntity.object3D!.position.set(0, 1.1, -1.5);
  settingsEntity.addComponent(PanelUI, { config: './ui/settings.json' });
  settingsEntity.object3D!.visible = false;

  // Skins
  const skinsEntity = world.createTransformEntity();
  skinsEntity.object3D!.position.set(0, 1.1, -1.5);
  skinsEntity.addComponent(PanelUI, { config: './ui/skins.json' });
  skinsEntity.object3D!.visible = false;

  // Help
  const helpEntity = world.createTransformEntity();
  helpEntity.object3D!.position.set(0, 1.0, -1.5);
  helpEntity.addComponent(PanelUI, { config: './ui/help.json' });
  helpEntity.object3D!.visible = false;

  // Leaderboard
  const lbEntity = world.createTransformEntity();
  lbEntity.object3D!.position.set(0, 1.0, -1.5);
  lbEntity.addComponent(PanelUI, { config: './ui/leaderboard.json' });
  lbEntity.object3D!.visible = false;

  // Countdown
  const cdEntity = world.createTransformEntity();
  cdEntity.object3D!.position.set(0, 1.4, -1.2);
  cdEntity.addComponent(PanelUI, { config: './ui/countdown.json' });
  cdEntity.object3D!.visible = false;

  // Toast (above everything)
  const toastEntity = world.createTransformEntity();
  toastEntity.object3D!.position.set(0, 2.1, -1.5);
  toastEntity.addComponent(PanelUI, { config: './ui/toast.json' });
  toastEntity.object3D!.visible = false;

  // Tutorial
  const tutEntity = world.createTransformEntity();
  tutEntity.object3D!.position.set(0, 1.1, -1.5);
  tutEntity.addComponent(PanelUI, { config: './ui/tutorial.json' });
  tutEntity.object3D!.visible = false;
}

main().catch(console.error);
